.darma-loader-darma-custom-345 {color: var(--loader-color, #2563eb);
  display: inline-grid;
  width: 80px;
  aspect-ratio: 1;
}.darma-loader-darma-custom-345:before,.darma-loader-darma-custom-345:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
}.darma-loader-darma-custom-345:before {margin: 25%;
  background: repeating-conic-gradient(var(--loader-color, #2563eb) 0 60deg,var(--loader-secondary-color, #38bdf8) 0 120deg);
  transform: rotate(0turn) translate(50%) rotate(0turn);
  animation: darma-loader-darma-custom-345-l2 2s alternate infinite ease-in-out;
}.darma-loader-darma-custom-345:after {padding: 10%;
  margin: -10%;
  background: repeating-conic-gradient(from -15deg,var(--loader-color, #2563eb) 0 30deg,var(--loader-secondary-color, #38bdf8) 0 60deg);
  mask: conic-gradient(from 75deg,currentColor 210deg,#0000 0) content-box exclude,conic-gradient(from 75deg,currentColor 210deg,#0000 0);
}@keyframes darma-loader-darma-custom-345-l2 {to{transform: rotate(.5turn) translate(50%) rotate(-1turn)}}

